AFTER (shared test fixture, e.g., __tests__/fixtures/test-images.ts):
  export async function createHorizontalSplitPng(width = 64, height = 64): Promise<Buffer> {
    const pixels = Buffer.alloc(width * height * 3)
    for (let y = 0; y < height; y++) {
      for (let x = 0; x < width; x++) {
        const i = (y * width + x) * 3
        const val = x < width / 2 ? 0 : 255
        pixels[i] = pixels[i + 1] = pixels[i + 2] = val
      }
    }
    return sharp(pixels, { raw: { width, height, channels: 3 } }).png().toBuffer()
  }

  export async function createVerticalSplitPng(width = 64, height = 64): Promise<Buffer> { ... }

WHY: Eliminates ~30 lines of copy-paste between two test files and creates a single source of truth for test image generation.

