  // In screenshot-pipeline.test.ts:
  class StubVlmProvider implements VlmProvider {
    callCount = 0
    async describeImage(): Promise<VlmResult> { this.callCount++; return { ... } }
  }

AFTER (shared in __tests__/fixtures/stub-vlm-provider.ts):
  export class StubVlmProvider implements VlmProvider {
    callCount = 0
    private result: VlmResult
    constructor(result?: Partial<VlmResult>) {
      this.result = {
        description: result?.description ?? 'User is browsing',
        entities: result?.entities ?? ['Chrome'],
        activity: result?.activity ?? 'browsing',
      }
    }
    async describeImage(_imageBuffer: Buffer): Promise<VlmResult> {
      this.callCount++
      return this.result
    }
  }

WHY: Merges both variants into a single configurable stub that supports both use cases (custom result + call counting). One place to update when VlmProvider interface evolves.

